FormulaFieldDefinitions.FormulaFieldDefinition:
IF({Header.MonEnabled} = 'Y') THEN
(
    stringvar timeString := ToText({Header.MonStart}, '#');
    while(Length(timeString) < 4) do timeString := '0'+timeString;
    timeString[1]+timeString[2]+':'+timeString[3]+timeString[4];
)
ELSE
'--:--'

